      ["coastal" /* coastal */]: this.options.coastal,
      ["land" /* land */]: this.options.land,
      ["sand" /* sand */]: this.options.sand,
      ["tundra" /* tundra */]: this.options.tundra,
      ["snow" /* snow */]: this.options.snow
